6: const Diacritic = enum(u8) {
7:     empty, // nguyên âm, không dấu.
8:     circumflex, // dấu nón: â, ô, ê.
9:     horn, // dấu móc: ư, ơ.
10:     breve, // dấu ă.
11:     stroke, // dấu gạch: đ.
12: };
13: 
14: const Tone = enum(u8) {
15:     level, // thanh ngang, không dấu.
16:     rising, // sắc.
17:     falling, // huyền.
18:     dipping_rising, // hỏi.
19:     rising_glottalized, // ngã.
20:     falling_glottalized, // nặng.
21: };
22: 
23: const Span = struct {
24:     // Alphabet ASCII character, could be lowercase or uppercase.
25:     base: u8,
26:     // By default, it's plain alphabet character.
27:     diacritic: Diacritic = .empty,
28:     // By default, no tone is placed.
29:     tone: Tone = .level,
30: 
31:     // Create a Span with plain alphabet character, no diacritic, no tone.
32:     fn init(base: u8) Span {
33:         return Span.init_diacritic_tone(base, .empty, .level);
34:     }
35: 
36:     // Create a Span with diacritic, no tone.
37:     fn init_diacritic(base: u8, diacritic: Diacritic) Span {
38:         return Span.init_diacritic_tone(base, diacritic, .level);
39:     }
40: 
41:     fn init_diacritic_tone(base: u8, diacritic: Diacritic, tone: Tone) Span {
42:         // Only allow a-zA-Z.
43:         assert(std.ascii.isAlphabetic(base));
44: 
45:         // Only allow a valid Vietnamese alphabet combinations.
46:         switch (diacritic) {
47:             // All alphabet is allowed without diacritic.
48:             .empty => {},
49:             // Only a, o, e are valid with circumflex.
50:             .circumflex => switch (base) {
51:                 'A', 'E', 'O', 'a', 'e', 'o' => {},
52:                 else => unreachable,
53:             },
54:             // Only u, o are valid with horn.
55:             .horn => switch (base) {
56:                 'O', 'U', 'o', 'u' => {},
57:                 else => unreachable,
58:             },
59:             // Only a is valid with breve.
60:             .breve => switch (base) {
61:                 'A', 'a' => {},
62:                 else => unreachable,
63:             },
64:             // Only d is valid with stroke.
65:             .stroke => switch (base) {
66:                 'D', 'd' => {},
67:                 else => unreachable,
68:             },
69:         }
70: 
71:         // Only allow tone on valid Vietnamese vowels based on Vietnamese rules.
72:         switch (tone) {
73:             // All alphabet is allowed with level.
74:             .level => {},
75:             // All vowels is allowed with remaining tones.
76:             .rising, .falling, .dipping_rising, .rising_glottalized, .falling_glottalized => switch (base) {
77:                 'A', 'E', 'I', 'O', 'U', 'Y', 'a', 'e', 'i', 'o', 'u', 'y' => {},
78:                 else => unreachable,
79:             },
80:         }
81: 
82:         return .{ .base = base, .diacritic = diacritic, .tone = tone };
83:     }
84: 
85:     // Compare the span with a base character (ignore case) and diacritic, tone is ignored.
86:     fn equals_ignore_case_and_tone(self: Span, base: u8, diacritic: Diacritic) bool {
87:         // Base must be alphabet letters.
88:         assert(std.ascii.isAlphabetic(base));
89: 
90:         return std.ascii.toUpper(self.base) == std.ascii.toUpper(base) and self.diacritic == diacritic;
91:     }
92: 
93:     // Compare only base character, ignore other aspects.
94:     fn equals_base(self: Span, base: u8) bool {
95:         // Base must be alphabet letters.
96: 
97:         return std.ascii.toUpper(self.base) == std.ascii.toUpper(base);
98:     }
99: };
