961: // Simple ABI wrapper for initialize allocated memory.
962: export fn lex_state_init(state: *anyopaque) void {
963:     // Ensure the allocated memory is aligned.
964:     assert(@intFromPtr(state) % @alignOf(State) == 0);
965: 
966:     const s: *State = @ptrCast(@alignCast(state));
967:     s.init();
968: }
969: 
970: // Needed for the caller to allocate memory for our State.
971: export const lex_state_size: usize = @sizeOf(State);
972: 
973: // Needed for the caller to allocate memory for our State.
974: export const lex_state_alignment: usize = @alignOf(State);
975: 
976: test "expect State can be initialized by raw allocation" {
977:     // Arrange
978: 
979:     // Allocate memory, only specify on this test to simulate runtime allocation.
980:     const raw_pointer = std.testing.allocator.rawAlloc(lex_state_size, .fromByteUnits(lex_state_alignment), @returnAddress()) orelse return error.OutOfMemory;
981:     defer std.testing.allocator.rawFree(raw_pointer[0..lex_state_size], .fromByteUnits(lex_state_alignment), @returnAddress());
982: 
983:     // Initialize state.
984:     lex_state_init(raw_pointer);
985:     const state: *align(lex_state_alignment) State = @ptrCast(@alignCast(raw_pointer));
986:     state.mode = .telex;
987: 
988:     const input_sequence = "bbbbbqqqqq";
989: 
990:     // Act
991:     for (input_sequence) |c| {
992:         lex_add(raw_pointer, c);
