999:     try expectEqual(null, state.buffer_modification_index);
1000:     // Because we didn't exceed the buffer_affective, don't set literal_index.
1001:     try expectEqual(null, state.literal_index);
1002:     // Don't touch on input mode.
1003:     try expectEqual(.telex, state.mode);
1004:     // Verify every the spans, must exactly the same with the input.
1005:     for (input_sequence, 0..) |c, i| {
1006:         const sp = state.buffer_effective[i];
1007:         try expectEqual(c, sp.base);
1008:         try expectEqual(.empty, sp.diacritic);
1009:         try expectEqual(.level, sp.tone);
1010:     }
1011: }
1012: 
1013: // Add operations to the given state based on Telex rules, operations are determined by the input
1014: // character.
1015: export fn lex_add(state: *anyopaque, c: u8) void {
1016:     const s: *State = @ptrCast(@alignCast(state));
1017:     s.add(c);
1018: }
1019: 
1020: export fn lex_backspace(state: *anyopaque) void {
1021:     const s: *State = @ptrCast(@alignCast(state));
1022:     s.backspace();
1023: }

